const rows = $input.all().map(i => i.json);
const weekStart = new Date();
weekStart.setDate(weekStart.getDate() - 7);
const weekStr = weekStart.toISOString().split('T')[0];
const today = new Date().toISOString().split('T')[0];

// Agent registry
const agentMap = {
  'JOB': 'Jeff', 'PERSONAL': 'Eilinaire', 'DEV': 'Krit',
  'BIZDEV': 'Nova', 'RESEARCH': 'Scout', 'HR': 'Vera',
  'FINANCE': 'Rex', 'QA': 'Quinn', 'LEGAL': 'Lex'
};

const activeAgents = rows.map(r => `${agentMap[r.pillar] || r.pillar}: ${r.task_count} tasks`);
const totalTasks = rows.reduce((sum, r) => sum + parseInt(r.task_count), 0);

// Detect idle agents (not in DB results)
const activePillars = rows.map(r => r.pillar);
const allPillars = Object.keys(agentMap);
const idleAgents = allPillars.filter(p => !activePillars.includes(p)).map(p => agentMap[p]);

const report = `## Vera Weekly Report — ${weekStr} to ${today}\n\n**Total tasks processed:** ${totalTasks}\n\n**Activity by Agent:**\n${activeAgents.join('\n')}\n\n**Idle agents (0 tasks this week):**\n${idleAgents.length > 0 ? idleAgents.join(', ') : 'None — all agents active'}\n\n**Status:** ${idleAgents.length > 3 ? '⚠️ Multiple idle agents — review capacity' : '✅ Balanced'}`;

return [{ json: { report, totalTasks, idleAgents, activeCount: rows.length, weekStr, today } }];

